/**
 * logies_dashboard.jsx
 * Controle logiesdecreet — 4×30-regel · Stad Leuven
 *
 * Two pages:
 *  - Dashboard  : existing flag table + detail panel
 *  - Kaartoverzicht : plain Leaflet map (imperative) with disc/size/flag filters + reg.nr. search
 *
 * Dependencies:
 *   npm install leaflet lucide-react
 */
