// ─── Map constants ────────────────────────────────────────────────────────────
// Hard-coded hex values because these are used in Leaflet's canvas context
// and inside react-leaflet Popup/Tooltip which live inside the same document.
const DISC_COLORS = {
  Hotel: '#377eb8',
  'B&B': '#a65628',
  Vakantiewoning: '#e41a1c',
  Hostel: '#984ea3',
  Camping: '#4daf4a',
  'Kamergerelateerde logies': '#ff7f00',
  Vakantiepark: '#ff7f00',
  Jeugdverblijf: '#f781bf',
};

const SIZE_BUCKETS = ['1', '2–9', '10–30', '31–75', '76–100', '101+'];
const SIZE_RADII = [5, 7, 10, 13, 16, 20]; // px, constant regardless of zoom

const FLAG_DEFS = [
  { key: 'ov', label: '4×30 — vergunning vereist', color: '#b91c1c' },
  { key: 'un', label: 'Gelijktijdige units', color: '#b45309' },
  { key: 'ca', label: 'Capaciteit overschreden', color: '#b45309' },
  { key: 'nk', label: 'Niet in basisregister', color: '#1d4ed8' },
  { key: 'ad', label: 'Adresafwijking', color: '#1d4ed8' },
];

function sizeRadius(n) {
  const thresholds = [1, 9, 30, 75, 100];
  for (let i = 0; i < thresholds.length; i++) {
    if (n <= thresholds[i]) return SIZE_RADII[i];
  }
  return SIZE_RADII[SIZE_RADII.length - 1];
}

function sizeBucket(n) {
  const thresholds = [1, 9, 30, 75, 100];
  for (let i = 0; i < thresholds.length; i++) {
    if (n <= thresholds[i]) return SIZE_BUCKETS[i];
  }
  return SIZE_BUCKETS[SIZE_BUCKETS.length - 1];
}

